// contexts/FormContext.tsx - Form state management
import React, { createContext, useContext, useState, useCallback, ReactNode } from 'react';
import { saveProgress, loadProgress, clearProgress } from '../utils/storageUtils';

interface FormData {
  fullName: string;
  dateOfBirth: string;
  sinNumber: string;
  email: string;
  phone: string;
  preferredContact: string;
  streetAddress: string;
  city: string;
  province: string;
  postalCode: string;
  isResident: string;
  residencyDuration: string;
  hasChildren: string;
  numberOfChildren: string;
  children: Array<{ childName: string; childDob: string }>;
  declarationAccepted: boolean;
  termsAccepted: boolean;
}

interface ValidationErrors {
  [field: string]: string;
}

interface FormContextType {
  formData: FormData;
  setFormData: React.Dispatch<React.SetStateAction<FormData>>;
  updateField: (field: keyof FormData, value: any) => void;
  validationErrors: ValidationErrors;
  setValidationErrors: React.Dispatch<React.SetStateAction<ValidationErrors>>;
  clearFieldError: (field: string) => void;
  isSubmitting: boolean;
  setIsSubmitting: React.Dispatch<React.SetStateAction<boolean>>;
  saveFormProgress: () => void;
  loadFormProgress: () => boolean;
  clearFormProgress: () => void;
  resetForm: () => void;
}

const initialFormData: FormData = {
  fullName: '',
  dateOfBirth: '',
  sinNumber: '',
  email: '',
  phone: '',
  preferredContact: '',
  streetAddress: '',
  city: '',
  province: 'Alberta',
  postalCode: '',
  isResident: '',
  residencyDuration: '',
  hasChildren: '',
  numberOfChildren: '',
  children: [],
  declarationAccepted: false,
  termsAccepted: false
};

const FormContext = createContext<FormContextType | undefined>(undefined);

export function FormProvider({ children }: { children: ReactNode }) {
  const [formData, setFormData] = useState<FormData>(initialFormData);
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const updateField = useCallback((field: keyof FormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    // Clear error when field is updated
    if (validationErrors[field]) {
      setValidationErrors(prev => {
        const updated = { ...prev };
        delete updated[field];
        return updated;
      });
    }
  }, [validationErrors]);

  const clearFieldError = useCallback((field: string) => {
    setValidationErrors(prev => {
      const updated = { ...prev };
      delete updated[field];
      return updated;
    });
  }, []);

  const saveFormProgress = useCallback(() => {
    saveProgress('acb-application', formData);
  }, [formData]);

  const loadFormProgress = useCallback(() => {
    const saved = loadProgress('acb-application');
    if (saved) {
      setFormData(saved);
      return true;
    }
    return false;
  }, []);

  const clearFormProgress = useCallback(() => {
    clearProgress('acb-application');
  }, []);

  const resetForm = useCallback(() => {
    setFormData(initialFormData);
    setValidationErrors({});
    clearFormProgress();
  }, [clearFormProgress]);

  return (
    <FormContext.Provider value={{
      formData,
      setFormData,
      updateField,
      validationErrors,
      setValidationErrors,
      clearFieldError,
      isSubmitting,
      setIsSubmitting,
      saveFormProgress,
      loadFormProgress,
      clearFormProgress,
      resetForm
    }}>
      {children}
    </FormContext.Provider>
  );
}

export function useForm() {
  const context = useContext(FormContext);
  if (!context) {
    throw new Error('useForm must be used within a FormProvider');
  }
  return context;
}

// routes/FormStep.tsx - Individual form step component
import React, { useMemo, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  GoabFormItem,
  GoabInput,
  GoabRadioGroup,
  GoabRadioItem,
  GoabCheckbox,
  GoabButton,
  GoabButtonGroup,
  GoabDatePicker,
  GoabCallout
} from '@abgov/react-components';
import { useForm } from '../contexts/FormContext';
import { validateStep, getFieldError } from '../utils/validationUtils';
import { stepConfig } from '../config/formConfig';

export function FormStep() {
  const { stepId } = useParams<{ stepId: string }>();
  const navigate = useNavigate();
  const { formData, updateField, validationErrors, setValidationErrors, saveFormProgress } = useForm();

  const currentStep = useMemo(() => {
    return stepConfig.find(s => s.id === stepId);
  }, [stepId]);

  const currentStepIndex = useMemo(() => {
    return stepConfig.findIndex(s => s.id === stepId);
  }, [stepId]);

  const totalSteps = stepConfig.length;

  const handleBack = useCallback(() => {
    saveFormProgress();
    if (currentStepIndex > 0) {
      navigate(`/apply/step/${stepConfig[currentStepIndex - 1].id}`);
    } else {
      navigate('/apply');
    }
  }, [currentStepIndex, navigate, saveFormProgress]);

  const handleContinue = useCallback(() => {
    if (!currentStep) return;

    const errors = validateStep(currentStep, formData);

    if (Object.keys(errors).length > 0) {
      setValidationErrors(errors);
      // Focus first error field
      const firstErrorField = Object.keys(errors)[0];
      document.querySelector(`[name="${firstErrorField}"]`)?.focus();
      return;
    }

    saveFormProgress();

    if (currentStepIndex < totalSteps - 1) {
      // Check for conditional next step
      let nextIndex = currentStepIndex + 1;
      while (nextIndex < totalSteps) {
        const nextStep = stepConfig[nextIndex];
        if (nextStep.conditional) {
          const conditionValue = formData[nextStep.conditional.field as keyof typeof formData];
          if (conditionValue?.toLowerCase() !== nextStep.conditional.value) {
            nextIndex++;
            continue;
          }
        }
        break;
      }

      if (nextIndex < totalSteps) {
        navigate(`/apply/step/${stepConfig[nextIndex].id}`);
      } else {
        navigate('/apply/review');
      }
    } else {
      navigate('/apply/review');
    }
  }, [currentStep, currentStepIndex, formData, navigate, saveFormProgress, setValidationErrors, totalSteps]);

  const handleFieldChange = useCallback((field: string, value: string | boolean) => {
    updateField(field as keyof typeof formData, value);
  }, [updateField]);

  const renderField = (question: any) => {
    const value = formData[question.field as keyof typeof formData];
    const error = validationErrors[question.field];

    switch (question.type) {
      case 'radio':
        return (
          <GoabFormItem
            key={question.field}
            label={question.label}
            error={error}
            requirement={question.required ? 'required' : 'optional'}
            helpText={question.helpText}
          >
            <GoabRadioGroup
              name={question.field}
              value={value as string}
              onChange={(e) => handleFieldChange(question.field, e.value)}
              error={!!error}
            >
              {question.options.map((option: string) => (
                <GoabRadioItem
                  key={option}
                  value={option.toLowerCase().replace(/\s+/g, '-')}
                  label={option}
                />
              ))}
            </GoabRadioGroup>
          </GoabFormItem>
        );

      case 'checkbox':
        return (
          <GoabFormItem
            key={question.field}
            error={error}
          >
            <GoabCheckbox
              name={question.field}
              checked={value as boolean}
              onChange={(e) => handleFieldChange(question.field, e.checked)}
              error={!!error}
              text={question.label}
            />
            {question.link && (
              <a href={question.link.url} target="_blank" rel="noopener noreferrer" className="help-link">
                {question.link.text}
              </a>
            )}
          </GoabFormItem>
        );

      case 'date':
        return (
          <GoabFormItem
            key={question.field}
            label={question.label}
            error={error}
            requirement={question.required ? 'required' : 'optional'}
            helpText={question.helpText}
          >
            <GoabDatePicker
              name={question.field}
              value={value as string}
              onChange={(e) => handleFieldChange(question.field, e.value)}
              error={!!error}
            />
          </GoabFormItem>
        );

      default:
        return (
          <GoabFormItem
            key={question.field}
            label={question.label}
            error={error}
            requirement={question.required ? 'required' : 'optional'}
            helpText={question.helpText}
          >
            <GoabInput
              name={question.field}
              type={question.type || 'text'}
              value={value as string}
              onChange={(e) => handleFieldChange(question.field, e.value)}
              error={!!error}
              width={question.width || '100%'}
            />
          </GoabFormItem>
        );
    }
  };

  if (!currentStep) {
    return <Navigate to="/apply" replace />;
  }

  const hasErrors = Object.keys(validationErrors).length > 0;

  return (
    <div className="form-page">
      <div className="form-header">
        <button type="button" className="back-link" onClick={handleBack}>
          Back
        </button>
        <p className="step-indicator">Step {currentStepIndex + 1} of {totalSteps}</p>
      </div>

      <h1 className="step-title">{currentStep.title}</h1>
      {currentStep.description && (
        <p className="step-description">{currentStep.description}</p>
      )}

      {hasErrors && (
        <div className="error-summary" role="alert">
          <h2 className="error-summary__heading">There is a problem</h2>
          <ul className="error-summary__list">
            {Object.entries(validationErrors).map(([field, error]) => (
              <li key={field}>
                <a href={`#${field}`}>{error}</a>
              </li>
            ))}
          </ul>
        </div>
      )}

      <form className="question-group" onSubmit={(e) => { e.preventDefault(); handleContinue(); }}>
        {currentStep.questions.map(renderField)}

        <div className="form-actions">
          <GoabButtonGroup alignment="start" gap="relaxed">
            <GoabButton type="primary" onClick={handleContinue}>
              Save and continue
            </GoabButton>
          </GoabButtonGroup>
        </div>
      </form>
    </div>
  );
}

// routes/ReviewPage.tsx - Review before submission
import React, { useCallback, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import {
  GoabButton,
  GoabButtonGroup,
  GoabCallout,
  GoabText
} from '@abgov/react-components';
import { useForm } from '../contexts/FormContext';
import { stepConfig } from '../config/formConfig';
import { formatDisplayDate } from '../utils/dateUtils';
import { submitApplication } from '../utils/apiUtils';

export function ReviewPage() {
  const navigate = useNavigate();
  const { formData, isSubmitting, setIsSubmitting, clearFormProgress } = useForm();
  const [submitError, setSubmitError] = useState<string | null>(null);

  const handleBack = useCallback(() => {
    // Go to last step
    const lastStep = stepConfig[stepConfig.length - 1];
    navigate(`/apply/step/${lastStep.id}`);
  }, [navigate]);

  const handleChange = useCallback((stepId: string) => {
    navigate(`/apply/step/${stepId}?return=review`);
  }, [navigate]);

  const handleSubmit = useCallback(async () => {
    setIsSubmitting(true);
    setSubmitError(null);

    try {
      const result = await submitApplication(formData);
      clearFormProgress();
      navigate('/apply/confirmation', { state: { referenceNumber: result.referenceNumber } });
    } catch (error) {
      console.error('Submission error:', error);
      setSubmitError('There was a problem submitting your application. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  }, [formData, navigate, setIsSubmitting, clearFormProgress]);

  const formatValue = (value: any, type?: string): string => {
    if (value === undefined || value === null || value === '') {
      return 'Not provided';
    }
    if (type === 'date') {
      return formatDisplayDate(value);
    }
    if (typeof value === 'boolean') {
      return value ? 'Yes' : 'No';
    }
    return String(value);
  };

  return (
    <div className="form-page">
      <div className="form-header">
        <button type="button" className="back-link" onClick={handleBack}>
          Back
        </button>
      </div>

      <h1 className="step-title">Review your application</h1>
      <p className="step-description">
        Check your answers before submitting. You can change any answer by clicking the Change link.
      </p>

      {submitError && (
        <GoabCallout type="emergency" heading="Submission failed">
          <GoabText mt="none" mb="none">{submitError}</GoabText>
        </GoabCallout>
      )}

      {stepConfig.map((step) => {
        // Skip conditional steps that don't apply
        if (step.conditional) {
          const conditionValue = formData[step.conditional.field as keyof typeof formData];
          if (conditionValue?.toString().toLowerCase() !== step.conditional.value) {
            return null;
          }
        }

        return (
          <div key={step.id} className="review-section">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <h3>{step.title}</h3>
              <button
                type="button"
                className="change-link"
                onClick={() => handleChange(step.id)}
              >
                Change
              </button>
            </div>

            {step.questions.map((question) => (
              <div key={question.field} className="review-item">
                <span className="review-item__question">{question.label}</span>
                <span className={
                  `review-item__answer ${!formData[question.field as keyof typeof formData] ? 'review-item__answer--empty' : ''}`
                }>
                  {formatValue(formData[question.field as keyof typeof formData], question.type)}
                </span>
              </div>
            ))}
          </div>
        );
      })}

      <GoabCallout type="information" heading="Ready to submit">
        <GoabText mt="none" mb="none">
          By submitting this application, you confirm that the information provided is true and complete.
        </GoabText>
      </GoabCallout>

      <div className="form-actions">
        <GoabButtonGroup alignment="start" gap="relaxed">
          <GoabButton
            type="primary"
            onClick={handleSubmit}
            disabled={isSubmitting}
          >
            {isSubmitting ? 'Submitting...' : 'Submit application'}
          </GoabButton>
          <GoabButton
            type="secondary"
            onClick={handleBack}
            disabled={isSubmitting}
          >
            Back
          </GoabButton>
        </GoabButtonGroup>
      </div>
    </div>
  );
}

